contracts/externelLibrary/libraryTypedSt.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract MyContract {
    // Address of the deployed MathsLibrary contract
    address constant MATH_LIBRARY_ADDRESS = 0x598F68376bCeA149d7b8DCEd0394B8e53cC95F11;

    function useLibraryFunction(uint256 a, uint256 b) public view returns (uint256) {
        (bool success, bytes memory returnData) = MATH_LIBRARY_ADDRESS.staticcall(
            abi.encodeWithSignature("mul(uint256,uint256)", a, b)
        );
        require(success, "Library call failed");

        return abi.decode(returnData, (uint256));
    }
}

